import{_ as t,o,c as a,ae as r}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Via Email Import","description":"","frontmatter":{"title":"Via Email Import","slug":"cost-data-via-email-import"},"headers":[],"relativePath":"marketer-hub/cost-data-via-email-import.md","filePath":"marketer-hub/cost-data-via-email-import.md"}'),i={name:"marketer-hub/cost-data-via-email-import.md"};function l(n,e,d,s,c,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>ROI Hub&#39;s email import functionality does several key things:</p><ol><li>It generates a unique email alias that you can give to your ad partner for them to send scheduled data to.</li><li>Data sent to the email alias gets piped to your Branch Dashboard reports, where you can analyze campaign performance across multiple ad partners at once.</li><li>It lets you test whether the format you and your ad partner are using to report cost data works with Branch.</li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>In order to start tracking cost data, you first need to:</p><ol><li><p>Create a <a href="https://dashboard.branch.io" target="_blank" rel="noreferrer">Branch Dashboard</a>.</p></li><li><p>Enable our <a href="./packaging.html#performance-pro-tier">Performance product</a> for your Branch account.</p><ol><li>Contact your Branch account manager or our <a href="https://www.branch.io/contact-sales" target="_blank" rel="noreferrer">sales team</a> to get started.</li></ol></li><li><p>Implement the Branch SDK into your mobile app (<a href="./ios-basic-integration.html">iOS</a> | <a href="./android-basic-integration.html">Android</a>).</p></li></ol><h2 id="file-templates" tabindex="-1">File Templates <a class="header-anchor" href="#file-templates" aria-label="Permalink to &quot;File Templates&quot;">​</a></h2><p>Before you can set up a cost data email importer, you first need to <a href="./templates-for-cost-data.html">create a file template</a>.</p><p>File templates help map your custom cost data fields to standard Branch fields.</p><h2 id="file-requirements" tabindex="-1">File Requirements <a class="header-anchor" href="#file-requirements" aria-label="Permalink to &quot;File Requirements&quot;">​</a></h2><ul><li><p>Your file can have any name, but it must be a CSV file and end with the <code>.csv</code> file extension.</p></li><li><p>For every row in your CSV, you <strong>must fill out the following columns</strong>:</p><ul><li><code>date</code> (use the format YYYY-MM-DD)</li><li><code>campaign_name</code></li><li><code>cost</code> (enter cost data in the format <code>1234.56</code> - do not include any currency symbols or commas)</li></ul></li><li><p><strong>If</strong> you fill out data for the <code>country_code</code> field, you must use the country code with capital letters, i.e. <code>FR</code> or <code>US</code>.</p></li><li><p><strong>If</strong> you fill out data for the <code>os</code> field, you must use one of the following values: <code>IOS</code>, <code>ANDROID</code>, <code>MAC_OS</code>, <code>WINDOWS</code>, <code>WINDOWS_PHONE</code>, <code>AMAZON_FIRE</code>, <code>AMAZON_FIRE_TV</code>, <code>ROKU</code>, <code>SAMSUNG</code>, <code>ANDROID_TV</code>, <code>LG</code>, <code>PANASONIC</code>, <code>TV_OS</code>, <code>CHROMECAST</code>, <code>PLAYSTATION</code>, <code>BADA</code>, <code>BEOS</code>, <code>BLACKBERRY</code>, <code>BSD</code>, <code>CENTOS</code>, <code>CHROMIUM_OS</code>, <code>DEBIAN</code>, <code>DRAGONFLY</code>, <code>FEDORA</code>, <code>FIREFOX_OS</code>, <code>FREEBSD</code>, <code>GENTOO</code>, <code>GNU</code>, <code>JOLI</code>, <code>KUBUNTU</code>, <code>LINUX</code>, <code>MANDRIVA</code>, <code>MEEGO</code>, <code>MINT</code>, <code>NETBSD</code>, <code>NINTENDO</code>, <code>OPENBSD</code>, <code>OS_2</code>, <code>RIM_TABLET_OS</code>, <code>SAILFISH</code>, <code>SLACKWARE</code>, <code>SOLARIS</code>, <code>SUSE</code>, <code>SYMBIAN</code>, <code>TIZEN</code>, <code>UBUNTU</code>, <code>UNIX</code>, <code>ZENWALK</code>, <code>XBOX</code>, <code>WEBOS</code>, <code>OTHER</code>, <code>ROBOTS</code>.</p></li></ul><h2 id="email-import-features" tabindex="-1">Email Import Features <a class="header-anchor" href="#email-import-features" aria-label="Permalink to &quot;Email Import Features&quot;">​</a></h2><p>Let&#39;s walk through the features of the <strong>Email Importers</strong> <a href="https://dashboard.branch.io/ads/roi-hub/import?section=email-importers" target="_blank" rel="noreferrer">view</a>, and see how to use each in turn.</p><p>First, click on the <strong>Import</strong> <a href="https://branch.dashboard.branch.io/ads/roi-hub/import" target="_blank" rel="noreferrer">tab</a> in ROI Hub. Then click on <strong>Email Importers</strong>.</p><h3 id="create-email-importer" tabindex="-1">Create Email Importer <a class="header-anchor" href="#create-email-importer" aria-label="Permalink to &quot;Create Email Importer&quot;">​</a></h3><p>To create a new email cost importer:</p><ol><li><p>Click the <strong>Set up Email Importer</strong> button in the upper right-side corner.</p></li><li><p>You will be taken to the <strong>Set up Email Importer</strong> page, where you need to fill out:</p><ol><li><p>Ad partner (required)</p><ol><li>You will only be able to select an ad partner if you have <a href="./templates-for-cost-data.html">created a file template associated with it</a>.</li></ol></li><li><p>Account ID (optional)</p><ol><li>You can find this on the <a href="https://dashboard.branch.io/ads/partner-management" target="_blank" rel="noreferrer">Ad Partner Settings page</a> for the ad partner.</li><li>This is important if you are uploading data for the same ad partner multiple times, as it might override existing data uploaded.</li></ol></li><li><p>Currency (required)</p></li><li><p>Email Importer name (required)</p><ol><li>A unique name for your Email Importer.</li><li>A name will be generated for you, which you can choose to use or edit.</li></ol></li><li><p>Permitted domains (required)</p><ol><li>Domains associated with the ad partner that you want to allow, and that Branch should expect files from. This could be their regular base domain, or it could be an obscure domain they send emails from, depending on the ad partner.</li></ol></li><li><p>Expected frequency (optional)</p><ol><li>How often you expect cost data to get sent to Branch.</li></ol></li></ol></li><li><p>The next step is optional, but we recommend uploading a sample CSV file that represents the kind of file you expect to be sent to Branch, so that you can validate the formatting.</p><p>In the <strong>Test sample file</strong> section, click the <strong>Upload</strong> button to upload the sample file. Then click the <strong>Run quick validation</strong> button.<br><em>[Image: 00c608d7c6ec61257fa278cb62e52b53404eceab2597280fa29de4f8d3091e06-Screenshot_2024-11-12_at_5.10.52_PM.png]</em>.png)</p></li><li><p>If your file is properly formatted, you will see a success message upon validation:<br><em>[Image: c861a37b12772e0558868707a3d27b5e37f3cca951bcb03aa38800431b189357-Screenshot_2024-11-12_at_5.13.47_PM.png]</em>.png)</p></li><li><p>Once your file has been validated, click the <strong>Generate Email Alias</strong> button. This button sets up the email importer and also creates an email address alias.</p><p>Note the email alias that gets generated. You will need to share this email alias with your ad partner so they can send cost data to Branch.</p></li></ol><h3 id="check-email-import-status" tabindex="-1">Check Email Import Status <a class="header-anchor" href="#check-email-import-status" aria-label="Permalink to &quot;Check Email Import Status&quot;">​</a></h3><p>To check the status of an email cost importer that you have created:</p><ol><li><p>Return to the <strong>Email Importers</strong> view of the <strong>Import</strong> tab.</p></li><li><p>If you recently created a new email cost importer, you will see it in the table, and it will have a status associated with it. It can be in one of the following states:</p><ul><li><strong>Pending</strong>: This is the initial state that the email importer goes into when you create it. It means the importer has been set up, but no emails have come through yet.</li><li><strong>Active</strong>: The first email has been imported and there were no errors.</li><li><strong>Error</strong>: The latest email import attempt failed. Visit the <a href="./cost-data-via-scheduled-ingestion.html#error-handling">Error Handling section</a> for more.</li></ul></li></ol><h3 id="filter-email-importers" tabindex="-1">Filter Email Importers <a class="header-anchor" href="#filter-email-importers" aria-label="Permalink to &quot;Filter Email Importers&quot;">​</a></h3><p>Once you&#39;ve created several Email Importers, you can begin to filter them by different attributes in the <a href="https://branch.dashboard.branch.io/ads/roi-hub/import?section=email-importers" target="_blank" rel="noreferrer">table</a>.</p><p>For example, you can filter by ad partner &quot;All&quot; and status &quot;Pending&quot; if you want to see all the Email Importers that have yet to have a full run. Or you can filter by status &quot;Error&quot; to see any that might need troubleshooting.</p><h2 id="error-handling" tabindex="-1">Error Handling <a class="header-anchor" href="#error-handling" aria-label="Permalink to &quot;Error Handling&quot;">​</a></h2><p>If your email cost importer is in the <strong>Failed</strong> state:</p><ol><li><p>Visit the <strong>Import History</strong> view and find the file that failed.</p></li><li><p>Click on <strong>View</strong> in the <strong>Actions</strong> column for the row that represents the file that failed.</p></li><li><p>You will see a detailed view of what caused the file to throw an error during ingestion.<br> There are a few different errors that might occur during the upload process, which mainly have to do with formatting.<br> These are the errors messages you might see, as well as their corresponding meaning:</p><ul><li><strong>Required fields are missing or formatted incorrectly</strong>: When any of the three required fields (<code>date</code>, <code>campaign_name</code> or <code>cost</code>) aren’t filled in or have the wrong format.</li><li><strong>Bad datatype or formatting detected</strong>: When the data in the column doesn’t match what’s expected (e.g. a value for <code>currency</code> is in the <code>cost</code> column).</li><li><strong>Fields contain values not currently supported</strong>: This is when the <code>country</code> or <code>os</code> column has a value that doesn’t match what is expected.</li><li><strong>Required fields do not exist in data file</strong>: This is when the column names <code>date</code>, <code>campaign_name</code>, or <code>cost</code> don’t exist in the file, or there are extra columns that don’t match the <a href="./cost-data-via-file-upload.html#file-template">template file</a>.</li></ul></li></ol>',26)])])}const u=t(i,[["render",l]]);export{p as __pageData,u as default};
